const express = require('express');
const crypto = require('crypto');

const app = express();
app.use(express.json({ limit: '256kb' }));

const PORT = process.env.PORT || 3000;
const API_KEY = process.env.API_KEY || 'dev-api-key-change-me';
const MAX_BODY_BYTES = 256 * 1024;

const db = {
  players: new Map(), // playerId -> { createdAt, lastSeenAt, levels: Map(levelId -> record), rewards: Map(rewardId -> reward) }
  claims: new Map(), // claimId -> { playerId, rewardId, createdAt, status }
};

function now() {
  return Date.now();
}

function sha256(input) {
  return crypto.createHash('sha256').update(input).digest('hex');
}

function randomId(prefix = '') {
  return prefix + crypto.randomBytes(16).toString('hex');
}

function getPlayer(playerId) {
  if (!db.players.has(playerId)) {
    db.players.set(playerId, {
      createdAt: now(),
      lastSeenAt: now(),
      levels: new Map(),
      rewards: new Map(),
    });
  }
  const p = db.players.get(playerId);
  p.lastSeenAt = now();
  return p;
}

function requireApiKey(req, res, next) {
  const key = req.header('x-api-key');
  if (!key || key !== API_KEY) return res.status(401).json({ error: 'unauthorized' });
  next();
}

function validateBodySize(req, res, next) {
  const len = Number(req.header('content-length') || 0);
  if (len > MAX_BODY_BYTES) return res.status(413).json({ error: 'payload_too_large' });
  next();
}

function isFiniteNumber(n) {
  return typeof n === 'number' && Number.isFinite(n);
}

function clampInt(n, min, max) {
  n = Math.trunc(n);
  if (n < min) return min;
  if (n > max) return max;
  return n;
}

function computeRewards({ levelId, score, timeMs, attempt }) {
  const rewards = [];

  const baseCoins = 10;
  const scoreCoins = clampInt(Math.floor(score / 100), 0, 500);
  const timeBonus = timeMs > 0 ? clampInt(Math.floor(600000 / timeMs), 0, 50) : 0;
  const attemptPenalty = clampInt((attempt - 1) * 2, 0, 20);

  const coins = Math.max(0, baseCoins + scoreCoins + timeBonus - attemptPenalty);
  if (coins > 0) rewards.push({ type: 'coins', amount: coins });

  const stars = clampInt(Math.floor(score / 1000) + (timeMs > 0 && timeMs <= 90000 ? 1 : 0), 0, 3);
  if (stars > 0) rewards.push({ type: 'stars', amount: stars });

  if (score >= 5000 && timeMs > 0 && timeMs <= 60000) {
    rewards.push({ type: 'booster', id: 'hint', amount: 1 });
  }

  const rewardId = sha256(`${levelId}:${score}:${timeMs}:${attempt}:${JSON.stringify(rewards)}`);
  return { rewardId, rewards };
}

function normalizeLevelId(levelId) {
  if (typeof levelId !== 'string') return null;
  const s = levelId.trim();
  if (!s || s.length > 64) return null;
  if (!/^[a-zA-Z0-9._:-]+$/.test(s)) return null;
  return s;
}

function normalizePlayerId(playerId) {
  if (typeof playerId !== 'string') return null;
  const s = playerId.trim();
  if (!s || s.length > 64) return null;
  if (!/^[a-zA-Z0-9._:-]+$/.test(s)) return null;
  return s;
}

app.get('/health', (req, res) => {
  res.json({ ok: true, time: new Date().toISOString() });
});

app.post('/v1/levels/complete', validateBodySize, requireApiKey, (req, res) => {
  const playerId = normalizePlayerId(req.body?.playerId);
  const levelId = normalizeLevelId(req.body?.levelId);
  const score = req.body?.score;
  const timeMs = req.body?.timeMs;
  const attempt = req.body?.attempt ?? 1;

  if (!playerId) return res.status(400).json({ error: 'invalid_playerId' });
  if (!levelId) return res.status(400).json({ error: 'invalid_levelId' });
  if (!isFiniteNumber(score) || score < 0 || score > 1e9) return res.status(400).json({ error: 'invalid_score' });
  if (!isFiniteNumber(timeMs) || timeMs < 0 || timeMs > 24 * 60 * 60 * 1000) return res.status(400).json({ error: 'invalid_timeMs' });
  if (!Number.isInteger(attempt) || attempt < 1 || attempt > 1000) return res.status(400).json({ error: 'invalid_attempt' });

  const player = getPlayer(playerId);
  const levels = player.levels;

  const prev = levels.get(levelId);
  const bestScore = prev ? Math.max(prev.bestScore, score) : score;
  const bestTimeMs = prev ? Math.min(prev.bestTimeMs, timeMs) : timeMs;
  const completions = prev ? prev.completions + 1 : 1;

  const completionId = randomId('cmp_');
  const completion = {
    completionId,
    playerId,
    levelId,
    score,
    timeMs,
    attempt,
    createdAt: now(),
  };

  levels.set(levelId, {
    levelId,
    bestScore,
    bestTimeMs,
    completions,
    lastCompletion: completion,
  });

  const { rewardId, rewards } = computeRewards({ levelId, score, timeMs, attempt });

  const rewardRecord = {
    rewardId,
    playerId,
    levelId,
    rewards,
    createdAt: now(),
    claimedAt: null,
    status: 'unclaimed',
    source: {
      score,
      timeMs,
      attempt,
      completionId,
    },
  };

  player.rewards.set(rewardId, rewardRecord);

  res.json({
    ok: true,
    completionId,
    level: {
      levelId,
      score,
      timeMs,
      attempt,
      bestScore,
      bestTimeMs,
      completions,
    },
    reward: {
      rewardId,
      status: rewardRecord.status,
      rewards,
    },
  });
});

app.post('/v1/rewards/claim', validateBodySize, requireApiKey, (req, res) => {
  const playerId = normalizePlayerId(req.body?.playerId);
  const rewardId = typeof req.body?.rewardId === 'string' ? req.body.rewardId.trim() : null;

  if (!playerId) return res.status(400).json({ error: 'invalid_playerId' });
  if (!rewardId || rewardId.length < 16 || rewardId.length > 128) return res.status(400).json({ error: 'invalid_rewardId' });

  const player = getPlayer(playerId);
  const reward = player.rewards.get(rewardId);

  if (!reward) return res.status(404).json({ error: 'reward_not_found' });

  if (reward.status === 'claimed') {
    return res.json({
      ok: true,
      rewardId,
      status: 'claimed',
      claimedAt: reward.claimedAt,
      rewards: reward.rewards,
      idempotent: true,
    });
  }

  const claimId = randomId('clm_');
  reward.status = 'claimed';
  reward.claimedAt = now();

  db.claims.set(claimId, {
    claimId,
    playerId,
    rewardId,
    createdAt: reward.claimedAt,
    status: 'claimed',
  });

  res.json({
    ok: true,
    claimId,
    rewardId,
    status: reward.status,
    claimedAt: reward.claimedAt,
    rewards: reward.rewards,
  });
});

app.get('/v1/players/:playerId/state', requireApiKey, (req, res) => {
  const playerId = normalizePlayerId(req.params.playerId);
  if (!playerId) return res.status(400).json({ error: 'invalid_playerId' });

  const player = getPlayer(playerId);

  const levels = [];
  for (const v of player.levels.values()) {
    levels.push({
      levelId: v.levelId,
      bestScore: v.bestScore,
      bestTimeMs: v.bestTimeMs,
      completions: v.completions,
      lastCompletion: v.lastCompletion,
    });
  }

  const rewards = [];
  for (const r of player.rewards.values()) {
    rewards.push({
      rewardId: r.rewardId,
      levelId: r.levelId,
      status: r.status,
      createdAt: r.createdAt,
      claimedAt: r.claimedAt,
      rewards: r.rewards,
      source: r.source,
    });
  }

  res.json({
    ok: true,
    playerId,
    createdAt: player.createdAt,
    lastSeenAt: player.lastSeenAt,
    levels,
    rewards,
  });
});

